<?php

function processXMLConfiguration($xmlContent) {
    if (empty($xmlContent)) {
        return ['error' => 'Empty XML content provided'];
    }
    
    libxml_use_internal_errors(true);
    libxml_disable_entity_loader(true);
    
    $cleanedXml = preg_replace('/<!DOCTYPE[^>]*>/i', '', $xmlContent);
    $cleanedXml = preg_replace('/<!ENTITY[^>]*>/i', '', $cleanedXml);
    
    $xml = simplexml_load_string(
        $cleanedXml,
        'SimpleXMLElement',
        LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR | LIBXML_NOCDATA
    );
    
    if ($xml === false) {
        $errors = [];
        foreach (libxml_get_errors() as $error) {
            $errors[] = sprintf(
                "Line %d: %s",
                $error->line,
                trim($error->message)
            );
        }
        libxml_clear_errors();
        return ['error' => 'XML parsing failed', 'details' => $errors];
    }
    
    $config = extractSettings($xml);
    
    return ['success' => true, 'config' => $config];
}

function extractSettings($xml) {
    $settings = [];
    
    foreach ($xml->children() as $element) {
        $name = $element->getName();
        
        if ($element->count() > 0) {
            $settings[$name] = extractSettings($element);
        } else {
            $attributes = [];
            foreach ($element->attributes() as $attrName => $attrValue) {
                $attributes[$attrName] = (string)$attrValue;
            }
            
            $value = (string)$element;
            
            if (!empty($attributes)) {
                $settings[$name] = [
                    'value' => $value,
                    'attributes' => $attributes
                ];
            } else {
                $settings[$name] = $value;
            }
        }
    }
    
    return $settings;
}

function validateXMLStructure($xmlContent, $requiredFields = []) {
    $result = processXMLConfiguration($xmlContent);
    
    if (isset($result['error'])) {
        return $result;
    }
    
    $config = $result['config'];
    $missing = [];
    
    foreach ($requiredFields as $field) {
        if (!isset($config[$field])) {
            $missing[] = $field;
        }
    }
    
    if (!empty($missing)) {
        return [
            'error' => 'Missing required fields',
            'missing_fields' => $missing
        ];
    }
    
    return ['success' => true, 'config' => $config];
}

function getConfigValue($config, $path, $default = null) {
    $keys = explode('.', $path);
    $value = $config;
    
    foreach ($keys as $key) {
        if (is_array($value) && isset($value[$key])) {
            $value = $value[$key];
        } else {
            return $default;
        }
    }
    
    return $value;
}

function saveConfigToFile($config, $filename) {
    $xml = new SimpleXMLElement('<?xml version="1.0" encoding="UTF-8"?><configuration></configuration>');
    arrayToXML($config, $xml);
    
    $dom = dom_import_simplexml($xml)->ownerDocument;
    $dom->formatOutput = true;
    
    return file_put_contents($filename, $dom->saveXML());
}

function arrayToXML($data, &$xml) {
    foreach ($data as $key => $value) {
        if (is_array($value)) {
            if (isset($value['value']) && isset($value['attributes'])) {
                $child = $xml->addChild($key, htmlspecialchars($value['value']));
                foreach ($value['attributes'] as $attrName => $attrValue) {
                    $child->addAttribute($attrName, $attrValue);
                }
            } else {
                $child = $xml->addChild($key);
                arrayToXML($value, $child);
            }
        } else {
            $xml->addChild($key, htmlspecialchars($value));
        }
    }
}

function mergeConfigurations($baseConfig, $overrideConfig) {
    foreach ($overrideConfig as $key => $value) {
        if (is_array($value) && isset($baseConfig[$key]) && is_array($baseConfig[$key])) {
            $baseConfig[$key] = mergeConfigurations($baseConfig[$key], $value);
        } else {
            $baseConfig[$key] = $value;
        }
    }
    return $baseConfig;
}

function loadXMLFromFile($filename) {
    if (!file_exists($filename)) {
        return ['error' => 'File not found'];
    }
    
    $xmlContent = file_get_contents($filename);
    return processXMLConfiguration($xmlContent);
}

function convertXMLToJSON($xmlContent) {
    $result = processXMLConfiguration($xmlContent);
    
    if (isset($result['error'])) {
        return json_encode($result);
    }
    
    return json_encode($result['config'], JSON_PRETTY_PRINT);
}

function searchConfigByKey($config, $searchKey) {
    $results = [];
    
    foreach ($config as $key => $value) {
        if ($key === $searchKey) {
            $results[$key] = $value;
        }
        
        if (is_array($value)) {
            $nested = searchConfigByKey($value, $searchKey);
            if (!empty($nested)) {
                $results[$key] = $nested;
            }
        }
    }
    
    return $results;
}

function flattenConfig($config, $prefix = '') {
    $result = [];
    
    foreach ($config as $key => $value) {
        $newKey = $prefix === '' ? $key : $prefix . '.' . $key;
        
        if (is_array($value)) {
            if (isset($value['value'])) {
                $result[$newKey] = $value['value'];
            } else {
                $result = array_merge($result, flattenConfig($value, $newKey));
            }
        } else {
            $result[$newKey] = $value;
        }
    }
    
    return $result;
}

